): Promise<NextResponse> {
  const { tenant } = await ctx.params;
  const config = getSnapshot();
  if (!config) {
    return NextResponse.json(
      { error: "Configuration not loaded" },
      { status: 503 },
    );
  }
  const tenantConfig = config.tenants[tenant];
  if (!tenantConfig) {
    return NextResponse.json({ error: "Unknown tenant" }, { status: 404 });
  }

  // TODO: implement POST handler
  return NextResponse.json({ status: "created", tenant }, { status: 201 });
}
```

## Process

1. Ask for the feature name if not provided as an argument
2. Create all directories and files from the templates above
3. Replace `<feature-name>` and `<Feature Name>` with the actual names
4. Run `npx biome check --write` on all created files
5. Report what was created and suggest next steps:
   - Add domain types and logic to `src/<feature-name>/`
   - Generate tests with `/gen-test`
   - Update `CLAUDE.md` if adding new dependencies

